// 1. سحب الرابط من نود الـ Form 
// تأكد أن 'Video Link' هو نفس الاسم الموجود في إعدادات الـ Form Trigger
const rawUrl = $input.first().json['Video Link'] || "";

// 2. تنظيف النص
const text = rawUrl.trim();

function getYouTubeID(url) {
    // مصفوفة الأنماط المدعومة (Watch, Shorts, Embed, Short-links)
    const patterns = [
        /v=([a-zA-Z0-9_-]{11})/,          
        /be\/([a-zA-Z0-9_-]{11})/,         
        /embed\/([a-zA-Z0-9_-]{11})/,       
        /shorts\/([a-zA-Z0-9_-]{11})/,      
        /vi\/([a-zA-Z0-9_-]{11})/           
    ];

    for (const pattern of patterns) {
        const match = url.match(pattern);
        if (match && match[1]) {
            return match[1];
        }
    }

    // محاولة أخيرة للروابط المعقدة
    const fallbackMatch = url.match(/[\/|=]([a-zA-Z0-9_-]{11})(?:[\?\&\s]|$)/);
    return fallbackMatch ? fallbackMatch[1] : null;
}

const videoId = getYouTubeID(text);

// 3. التحقق النهائي قبل الإرسال لـ Notion أو الـ HTTP Request
if (!videoId) {
    throw new Error(`لم نتمكن من استخراج ID الفيديو. الرابط المستلم: "${text}"`);
}

return {
    videoId: videoId,
    originalUrl: text
};
